export default function App() {
  const [screen, setScreen] = useState("home");
  const [activeCat, setActiveCat] = useState(null);
  const [activeTopic, setActiveTopic] = useState(null);
  const [activeQ, setActiveQ] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);

  const cat = categories.find((c) => c.id === activeCat);
  const topic = cat?.topics[activeTopic];

  if (screen === "home") {
    return (
      <div style={s.root}>
        <style>{css}</style>
        {/* Hero */}
        <div style={s.hero}>
          <div style={s.heroEmblem}>🇹🇷</div>
          <div style={s.heroTitle}>SÖZLÜ MÜLAKAT</div>
          <div style={s.heroSub}>HAZIRLIK PLATFORMU</div>
          <div style={s.heroDivider} />
        </div>

        {/* Cards - horizontal scroll */}
        <div style={s.scrollWrap}>
          <div style={s.scrollRow}>
            {categories.map((c, i) => (
              <div
                key={c.id}
                className="hero-card"
                style={{
                  ...s.heroCard,
                  background: `linear-gradient(160deg, ${c.color1} 0%, ${c.color2} 100%)`,
                  animationDelay: `${i * 0.15}s`,
                }}
                onClick={() => { setActiveCat(c.id); setScreen("category"); }}
              >
                {/* Top stripe */}
                <div style={{ ...s.cardStripe, background: c.accent }} />

                <div style={s.heroCardIcon}>{c.icon}</div>
                <div style={{ ...s.heroCardTitle, color: c.accent }}>{c.label}</div>
                <div style={s.heroCardSub}>{c.sublabel}</div>

                <div style={s.tagWrap}>
                  {c.tags.map((t) => (
                    <span key={t} style={{ ...s.pill, color: c.accent, borderColor: `${c.accent}55` }}>{t}</span>
                  ))}
                </div>

                <div style={{ ...s.cardCta, background: c.accent }}>
                  <span style={{ color: "#000", fontWeight: 800, fontSize: 13, letterSpacing: 1 }}>BAŞLA</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={s.bottomNote}>Sözlüde parlama için en güçlü hazırlık</div>
      </div>
    );
  }

  // SUBCATEGORY EKRANI
  if (screen === "subcats" && cat) {
    const subs = subcategories[cat.id] || [];
    return (
      <div style={{ ...s.root, background: `linear-gradient(180deg, ${cat.color1} 0%, #050505 100%)` }}>
        <style>{css}</style>
        <div style={s.topBar}>
          <button style={s.back} onClick={() => setScreen("home")}>‹</button>
          <span style={{ ...s.topTitle, color: cat.accent }}>{cat.icon} {cat.label}</span>
          <div style={{ width: 32 }} />
        </div>
        <div style={{ padding: "20px 16px", display: "flex", flexDirection: "column", gap: 14 }}>
          {subs.map((sub, i) => (
            <div
              key={i}
              className="topic-row"
              style={{ ...s.topicRow, borderLeft: `4px solid ${cat.accent}`, opacity: sub.id === "pomem" ? 1 : 0.5 }}
              onClick={() => {
                if (sub.id === "pomem") {
                  setActiveSubcat(sub.id);
                  setScreen("category");
                }
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
                <div style={{ fontSize: 28 }}>{sub.icon}</div>
                <div>
                  <div style={{ color: "#fff", fontWeight: 800, fontSize: 16 }}>{sub.label}</div>
                  <div style={{ color: "#888", fontSize: 12, marginTop: 3 }}>{sub.desc}</div>
                </div>
              </div>
              <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 4 }}>
                {sub.id === "pomem" ? (
                  <span style={{ color: cat.accent, fontSize: 22 }}>›</span>
                ) : (
                  <span style={{ background: "#ffffff15", color: "#666", fontSize: 10, borderRadius: 10, padding: "3px 8px" }}>Yakında</span>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (screen === "category" && cat) {
    return (
      <div style={{ ...s.root, background: `linear-gradient(180deg, ${cat.color1} 0%, #050505 100%)` }}>
        <style>{css}</style>
        <div style={s.topBar}>
          <button style={s.back} onClick={() => setScreen("home")}>‹</button>
          <span style={{ ...s.topTitle, color: cat.accent }}>{cat.icon} {cat.label}</span>
          <div style={{ width: 32 }} />
        </div>
        <div style={{ padding: "20px 16px", display: "flex", flexDirection: "column", gap: 14 }}>
          {cat.topics.map((t, i) => {
            const typeMap = {
              info: { icon: "ℹ️", label: "Bilgi", color: "#38bdf8" },
              requirements: { icon: "📌", label: "Şartlar", color: "#fb7185" },
              proverb: { icon: "📜", label: "Atasözü", color: "#c084fc" },
              experience: { icon: "💬", label: "Deneyim", color: "#a78bfa" },
              regulation: { icon: "📋", label: "Yönetmelik", color: "#34d399" },
              school: { icon: "🏫", label: "Okul", color: "#60a5fa" },
              exam: { icon: "📝", label: "Çıkmış Soru", color: "#fbbf24" },
              parkur: { icon: "🏃", label: "Parkur", color: "#fb923c" },
              kpss: { icon: "📊", label: "KPSS Puanları", color: "#facc15" },
              lessons: { icon: "📚", label: "Dersler", color: "#818cf8" },
              ebook: { icon: "📖", label: "E-Kitap", color: "#f472b6" },
            };
            const meta = typeMap[t.type] || { icon: "📚", label: "Konu", color: cat.accent };
            return (
              <div
                key={i}
                className="topic-row"
                style={{ ...s.topicRow, borderLeft: `4px solid ${meta.color}` }}
                onClick={() => { setActiveTopic(i); setActiveQ(0); setShowAnswer(false); setScreen("topic"); }}
              >
                <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
                  <div style={{ fontSize: 26 }}>{meta.icon}</div>
                  <div>
                    <div style={{ color: "#fff", fontWeight: 700, fontSize: 15 }}>{t.title}</div>
                    <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 4 }}>
                      <span style={{ background: `${meta.color}22`, color: meta.color, fontSize: 10, fontWeight: 700, borderRadius: 20, padding: "2px 8px", letterSpacing: 1 }}>{meta.label}</span>
                      <span style={{ color: "#666", fontSize: 12 }}>{t.questions.length} soru</span>
                    </div>
                  </div>
                </div>
                <span style={{ color: meta.color, fontSize: 22 }}>›</span>
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  if (screen === "topic" && topic) {
    if (topic.listMode) {
      return (
        <div style={{ ...s.root, background: `linear-gradient(180deg, ${cat.color1} 0%, #050505 100%)` }}>
          <style>{css}</style>
          <div style={s.topBar}>
            <button style={s.back} onClick={() => setScreen("category")}>‹</button>
            <span style={{ ...s.topTitle, color: cat.accent }}>{topic.title}</span>
            <div style={{ width: 32 }} />
          </div>
          <div style={{ padding: "16px", display: "flex", flexDirection: "column", gap: 16, overflowY: "auto" }}>
            {topic.parkurImages && topic.parkurImages.map((img, i) => (
              <div key={i} style={{ borderRadius: 12, overflow: "hidden", border: `2px solid ${cat.accent}` }}>
                <div style={{ background: cat.accent, padding: "8px 12px", color: "#000", fontWeight: 800, fontSize: 13 }}>{img.label}</div>
                <img src={img.src} alt={img.label} style={{ width: "100%", display: "block" }} />
              </div>
            ))}
            {topic.items && topic.items.map((item, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, background: "#ffffff08", borderRadius: 10, padding: "14px 16px", borderLeft: `4px solid ${cat.accent}` }}>
                <span style={{ color: cat.accent, fontWeight: 800, fontSize: 13, minWidth: 26 }}>{i + 1}.</span>
                {item.startsWith("http") || item.includes("instagram.com") ? (
                <a href={item} target="_blank" rel="noreferrer" style={{ color: "#818cf8", fontSize: 14, lineHeight: 1.5, wordBreak: "break-all" }}>{item}</a>
              ) : (
                <span style={{ color: "#ddd", fontSize: 14, lineHeight: 1.5 }}>{item}</span>
              )}
              </div>
            ))}
          </div>
        </div>
      );
    }
    return (
      <div style={{ ...s.root, background: `linear-gradient(180deg, ${cat.color1} 0%, #050505 100%)` }}>
        <style>{css}</style>
        <div style={s.topBar}>
          <button style={s.back} onClick={() => setScreen("category")}>‹</button>
          <span style={{ ...s.topTitle, color: cat.accent }}>{topic.title}</span>
          <div style={{ width: 32 }} />
        </div>
        <div style={{ padding: "20px 16px", display: "flex", flexDirection: "column", gap: 12 }}>
          {topic.questions.map((item, i) => (
            <div
              key={i}
              className="topic-row"
              style={{ ...s.topicRow, borderLeft: `4px solid ${cat.accent}` }}
              onClick={() => { setActiveQ(i); setShowAnswer(false); setScreen("question"); }}
            >
              <div style={{ color: "#ddd", fontSize: 14, flex: 1, paddingRight: 12 }}>{item.q}</div>
              <span style={{ color: cat.accent, fontSize: 22, flexShrink: 0 }}>›</span>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (screen === "question" && topic) {
    const item = topic.questions[activeQ];
    return (
      <div style={{ ...s.root, background: `linear-gradient(180deg, ${cat.color1} 0%, #050505 100%)` }}>
        <style>{css}</style>
        <div style={s.topBar}>
          <button style={s.back} onClick={() => { setShowAnswer(false); setScreen("topic"); }}>‹</button>
          <span style={{ color: "#aaa", fontSize: 13 }}>{activeQ + 1} / {topic.questions.length}</span>
          <div style={{ width: 32 }} />
        </div>

        {/* Progress bar */}
        <div style={s.progressBg}>
          <div style={{ ...s.progressFill, background: cat.accent, width: `${((activeQ + 1) / topic.questions.length) * 100}%` }} />
        </div>

        <div style={{ padding: "24px 16px", display: "flex", flexDirection: "column", gap: 18, flex: 1 }}>
          <div style={{ ...s.qCard, borderTop: `3px solid ${cat.accent}` }}>
            <div style={{ color: cat.accent, fontSize: 11, letterSpacing: 3, marginBottom: 12, fontWeight: 700 }}>SORU</div>
            <div style={{ color: "#fff", fontSize: 17, lineHeight: 1.7, fontWeight: 600 }}>{item.q}</div>
          </div>

          {!showAnswer ? (
            <button
              className="reveal-btn"
              style={{ ...s.revealBtn, background: cat.accent }}
              onClick={() => setShowAnswer(true)}
            >
              CEVABI GÖR
            </button>
          ) : (
            <div style={{ ...s.qCard, borderTop: `3px solid #ffffff33` }} className="answer-in">
              <div style={{ color: "#aaa", fontSize: 11, letterSpacing: 3, marginBottom: 12, fontWeight: 700 }}>CEVAP</div>
              <div style={{ color: cat.textAccent, fontSize: 16, lineHeight: 1.8 }}>{item.a}</div>
            </div>
          )}

          <div style={s.navRow}>
            <button
              style={{ ...s.navBtn, borderColor: activeQ === 0 ? "#222" : cat.accent, color: activeQ === 0 ? "#333" : cat.accent }}
              disabled={activeQ === 0}
              onClick={() => { setActiveQ(activeQ - 1); setShowAnswer(false); }}
            >‹ Önceki</button>
            <button
              style={{ ...s.navBtn, borderColor: activeQ === topic.questions.length - 1 ? "#222" : cat.accent, color: activeQ === topic.questions.length - 1 ? "#333" : cat.accent }}
              disabled={activeQ === topic.questions.length - 1}
              onClick={() => { setActiveQ(activeQ + 1); setShowAnswer(false); }}
            >Sonraki ›</button>
          </div>
        </div>
      </div>
    );
  }

  return null;
}

